import type { UmbSubmittableWorkspaceContext } from "@umbraco-cms/backoffice/workspace";
import type { UmbControllerHostElement } from "@umbraco-cms/backoffice/controller-api";
import type { FormSecurityForUser } from "@umbraco-forms/generated";
import { FORMS_SECURITY_USER_ENTITY_TYPE } from "../entities.js";
import { FormsSecurityUserDetailRepository } from "../repository/index.js";
import { FORMS_SECURITY_USER_WORKSPACE_ALIAS } from "./manifests.js";
import { FormsSecurityUserWorkspaceEditorElement } from "./security-user-workspace-editor.element.js";
import { FormsSecurityWorkspaceBaseContext } from "./security-workspace-base.context.js";

export class FormsSecurityUserWorkspaceContext
  extends FormsSecurityWorkspaceBaseContext<FormSecurityForUser>
  implements UmbSubmittableWorkspaceContext
{
  constructor(host: UmbControllerHostElement) {
    super(
      host,
      FORMS_SECURITY_USER_WORKSPACE_ALIAS,
      FORMS_SECURITY_USER_ENTITY_TYPE,
      FormsSecurityUserDetailRepository,
      FormsSecurityUserWorkspaceEditorElement
    );
  }

  setUserSecurityProperty(alias: string, value: boolean) {
    if (!this._data.value) return;

    const userSecurity = structuredClone(this._data.value.userSecurity);
    userSecurity[alias] = value;
    this._data.update({ userSecurity });
  }
}

export const api = FormsSecurityUserWorkspaceContext;
